import{_ as o,o as a,c as t,a3 as i}from"./chunks/framework.CjquFG0V.js";const f=JSON.parse('{"title":"56. Family Violence Leave","description":"","frontmatter":{"title":"56. Family Violence Leave","eba":"Biomedical Engineers 2025-2028","topics":["leave","family-violence-leave","preliminary"]},"headers":[],"relativePath":"ebas/biomedical-engineers/leave/56-family-violence-leave.md","filePath":"ebas/biomedical-engineers/leave/56-family-violence-leave.md"}'),n={name:"ebas/biomedical-engineers/leave/56-family-violence-leave.md"};function r(s,e,l,p,c,m){return a(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="_56-family-violence-leave" tabindex="-1">56. Family Violence Leave <a class="header-anchor" href="#_56-family-violence-leave" aria-label="Permalink to &quot;56. Family Violence Leave&quot;">​</a></h1><p>NOTE: The definition of family member in this clause is broader than the definition of Immediate Family in <a href="/eba/ebas/allied-health/preliminary/4-definitions.html">clause 4.10</a> (Definitions).</p><p><strong>56.1</strong> Each Employer recognises that Employees sometimes face situations of violence or abuse in their personal life that may affect their attendance or performance at work. Therefore, each Employer is committed to providing support to staff that experience family violence.</p><p><strong>56.2</strong> The Employer will develop guidelines to supplement this clause which details the appropriate action to be taken in the event that an Employee discloses family violence.</p><p><strong>56.3</strong> Definitions</p><p><strong>(a)</strong> In this Agreement, ‘Family Violence’ has the same meaning as the Family Violence Protection Act 2008 (Vic) (Family Violence Act) and also has the same meaning as ‘Family and Domestic Violence’ in the NES.</p><p><strong>(i)</strong> Under the Family Violence Act, ‘Family Violence’ is defined, in part, as: <strong>(A)</strong> behaviour by a person towards a family member of that person if the behaviour is: (1) physically or sexually abusive; or (2) emotionally or psychologically abusive; or (3) economically abusive; or (4) threatening; or (5) coercive; or (6) in any other way controls or dominates the family member and causes that family member to feel fear for the safety or wellbeing of that family member or another person; or <strong>(B)</strong> behaviour by a person that causes a child to hear or witness, or otherwise be exposed to the effects of, behaviour referred to in subclause 56.3(a)(i)(A).</p><p><strong>(ii)</strong> Under the NES, the definition of Family and Domestic Violence is violent, threatening or other abusive behaviour by an Employee&#39;s close relative (as defined under the Act), Employee’s household, or a current or former intimate</p><p>partner of an Employee that seeks to coerce or control the Employee and causes the Employee harm or to be fearful.</p><p><strong>(b)</strong> Affected Employee means an Employee experiencing Family Violence as defined.</p><p><strong>56.4</strong> Amount of Leave</p><p><strong>(a)</strong> An Affected full-time Employee will have access to 20 days per year of paid family violence leave.</p><p><strong>(b)</strong> An Affected part-time Employee who works 19 ordinary hours or more per week will have access to 20 days per year of paid family violence leave on a pro-rata basis and a balance of unpaid family violence leave days so that the Employee has access to 20 days family violence leave in total per year.</p><p>Example: A part-time Employee is 0.75 EFT, meaning they can access 15 days of family violence leave per year (the pro-rata entitlement of 20 days paid family violence leave per year). They would therefore be able to access a further 5 days of unpaid family violence leave per year for a total of 20 days of family violence leave per year they can access.</p><p><strong>(c)</strong> An Affected part-time Employee who works below 19 ordinary hours per week will have access to 10 days per year (not pro-rata) of paid family violence leave and 10 days of unpaid family violence leave.</p><p><strong>(d)</strong> An Affected casual Employee will have access to 10 days per year (not pro-rata) of paid family violence leave and 10 days of unpaid family violence leave.</p><p><strong>(e)</strong> Family violence leave is available in full at the start of each 12-month period of the Employee&#39;s employment.</p><p><strong>56.5</strong> Taking of Leave</p><p><strong>(a)</strong> An Affected Employee may take family violence leave where they require time release for activities related to and as a consequence of family violence including:</p><p><strong>(i)</strong> accessing police services;</p><p><strong>(ii)</strong> medical and legal assistance;</p><p><strong>(iii)</strong> court appearances/hearings;</p><p><strong>(iv)</strong> counselling (including financial counselling/assistance);</p><p><strong>(v)</strong> relocation;</p><p><strong>(vi)</strong> making safety arrangements.</p><p><strong>(b)</strong> An Employee who supports a family member or household member experiencing Family Violence may also utilise their personal leave entitlement to accompany the family member or household member to court, to hospital, or to care for children.</p><p><strong>(c)</strong> The leave may be taken as consecutive or single days or as a fraction of a day.</p><p><strong>(d)</strong> The leave does not accumulate from year to year.</p><p><strong>56.6</strong> Payment of Leave</p><p><strong>(a)</strong> Where an Affected Employee takes a period of family violence leave under this clause 56, the Employer must pay the Employee, in relation to the period:</p><p><strong>(i)</strong> for an Employee other than a casual Employee — at the Employee’s full rate of pay, worked out as if the Employee had not taken the period of leave;</p><p><strong>(ii)</strong> for a casual Employee — at the Employee’s full rate of pay, worked out as if the Employee had worked the hours in the period for which the casual Employee was rostered.</p><p><strong>(b)</strong> Without limiting subclause 56.6(a)(ii), a casual Employee is taken to have been rostered to work hours in a period if the Employee has accepted an offer by the Employer of work for those hours.</p><p><strong>(c)</strong> Subclause 56.6(a)(ii) does not prevent a casual Employee from taking a period of paid family violence leave that does not include hours for which the casual Employee is rostered to work. However, the Employer is not required to pay the casual Employee in relation to such a period.</p><p><strong>56.7</strong> Designated Contact Point The Employer will identify contact/s within the workplace who will be trained in family violence and associated privacy issues. Employees will be advised of the designated contact point(s).</p><p><strong>56.8</strong> Disclosure of Family Violence and Support</p><p><strong>(a)</strong> An affected Employee may disclose they are experiencing family violence to either their immediate supervisor or the designated contact point.</p><p><strong>(b)</strong> Where an affected Employee makes a disclosure to their immediate supervisor, the supervisor will advise the designated contact point.</p><p><strong>(c)</strong> Following consultation with the affected Employee, the relevant supervisor and designated contact point shall:</p><p><strong>(i)</strong> Implement reasonable measures to manage any potential risk to health and safety. Such measures may include: <strong>(A)</strong> changing the affected Employee’s hours of work, duties, location of work or contact details; <strong>(B)</strong> advising security staff consistent with the Employer’s occupational violence policy where applicable; <strong>(C)</strong> any other appropriate measure including those available under existing provisions for family friendly and flexible work arrangements. Changes to work arrangements may be agreed on a temporary or ongoing basis having regard to the circumstance. Periods of review should also be agreed.</p><p><strong>(ii)</strong> Offer the affected Employee access to the Employer’s ‘Employee Assistance Program’ (EAP) and/or other available local support resources. Where possible, the EAP will include professionals trained in family violence.</p><p><strong>(iii)</strong> Provide information regarding current support services.</p><p><strong>(d)</strong> Where the performance or attendance of an Employee at work suffers as a result of being a victim of family violence, the Employer shall:</p><p><strong>(i)</strong> take into account the effect of the family violence; and</p><p><strong>(ii)</strong> take all reasonable measures to support attendance and / or performance when addressing the Employee’s performance or attendance, taking into account all of the relevant circumstances.</p><p><strong>56.9</strong> Confidentiality</p><p><strong>(a)</strong> All personal information concerning family violence will be kept confidential in line with the Employer’s policies and relevant legislation.</p><p><strong>(b)</strong> An Employer must not, other than with the consent of the Affected Employee, use such information for a purpose other than satisfying itself in relation to the Employee’s entitlement to leave under this clause. In particular, an Employer must not use such information to take adverse action against an Affected Employee.</p><p><strong>(c)</strong> Subclause 56.9(b) has effect subject to subclause 56.9(d).</p><p><strong>(d)</strong> Nothing in this clause 56 prevents an Employer from dealing with information provided by an Affected Employee if doing so is required by an Australian law or is necessary to protect the life, health or safety of the Employee or another person. Note: Information covered by this clause that is personal information may also be regulated under the Privacy Act 1988 (Cth).</p><p><strong>56.10</strong> Notice and Evidence Requirements</p><p><strong>(a)</strong> Notice Requirements The leave can be taken without prior approval where it is impractical for the affected Employee to provide notice of taking the leave.</p><p><strong>(b)</strong> Evidence Requirements</p><p><strong>(i)</strong> An affected Employee may be required by the Employer to provide evidence that their absence is due to the reasons specified in subclauses 56.5(a) and/or (b).</p><p><strong>(ii)</strong> If required, such evidence will be in the form of an agreed document issued by a medical practitioner, Registered Health Practitioner, Police service, Court, Family Violence Support Service, social support service, financial counsellor or Lawyer. A statutory declaration may also be used.</p><p>Plain language terms: DV leave, domestic violence.</p>',56)])])}const d=o(n,[["render",r]]);export{f as __pageData,d as default};
